<?php

namespace App\Services\Providers;

class DemoWeatherProvider implements WeatherProviderInterface
{
    public function getForecast(float $lat, float $lng, \DateTime $date): array
    {
        $month = (int) $date->format('n');
        $isWinter = in_array($month, [11, 12, 1, 2]);
        $isSummer = in_array($month, [6, 7, 8]);
        $isSpring = in_array($month, [3, 4, 5]);

        $baseTemp = match(true) {
            $isWinter => rand(2, 8),
            $isSpring => rand(8, 16),
            $isSummer => rand(16, 26),
            default => rand(10, 18),
        };

        $conditions = $isSummer
            ? ['Partly Cloudy', 'Sunny', 'Clear Skies', 'Light Breeze', 'Warm & Overcast']
            : ($isWinter
                ? ['Overcast', 'Light Rain', 'Cold & Clear', 'Drizzle', 'Foggy Morning']
                : ['Partly Cloudy', 'Light Showers', 'Mild & Breezy', 'Overcast', 'Sunny Spells']);

        $hours = [];
        for ($h = 5; $h <= 21; $h++) {
            $tempVariation = rand(-3, 3);
            $hourTemp = max(0, $baseTemp + $tempVariation + ($h >= 12 && $h <= 15 ? 3 : -1));
            $hours[] = [
                'hour' => sprintf('%02d:00', $h),
                'temp_c' => $hourTemp,
                'feels_like_c' => $hourTemp - rand(0, 3),
                'condition' => $conditions[array_rand($conditions)],
                'wind_mph' => rand(3, 25),
                'wind_direction' => ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'][array_rand(['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'])],
                'precipitation_chance' => rand(0, 60),
                'humidity' => rand(50, 90),
            ];
        }

        return [
            'date' => $date->format('Y-m-d'),
            'location' => ['lat' => $lat, 'lng' => $lng],
            'summary' => $conditions[0] . ", highs of {$baseTemp}°C with " . rand(5, 20) . "mph winds",
            'high_c' => $baseTemp + 3,
            'low_c' => $baseTemp - 4,
            'avg_wind_mph' => rand(5, 20),
            'precipitation_chance' => rand(10, 60),
            'sunrise' => $isSummer ? '05:15' : ($isWinter ? '07:45' : '06:30'),
            'sunset' => $isSummer ? '21:15' : ($isWinter ? '16:00' : '18:45'),
            'uv_index' => $isSummer ? rand(5, 9) : rand(1, 4),
            'pressure_mb' => rand(1005, 1030),
            'hourly' => $hours,
        ];
    }

    public function getProviderName(): string
    {
        return 'demo';
    }
}
</boltAction>

<boltAction type="file" filePath="app/Services/Providers/DemoTideProvider.php" contentType="text/plain">
<?php

namespace App\Services\Providers;

class DemoTideProvider implements TideProviderInterface
{
    public function getTides(float $lat, float $lng, \DateTime $date): array
    {
        $baseHour = rand(0, 5);
        $tides = [];

        for ($i = 0; $i < 4; $i++) {
            $hour = ($baseHour + ($i * 6) + rand(0, 1)) % 24;
            $minute = rand(0, 59);
            $isHigh = $i % 2 === 0;
            $height = $isHigh ? round(rand(40, 70) / 10, 1) : round(rand(5, 20) / 10, 1);

            $tides[] = [
                'time' => sprintf('%02d:%02d', $hour, $minute),
                'type' => $isHigh ? 'high' : 'low',
                'height_m' => $height,
            ];
        }

        usort($tides, fn($a, $b) => strcmp($a['time'], $b['time']));

        $tidalRange = abs(($tides[0]['height_m'] ?? 0) - ($tides[1]['height_m'] ?? 0));

        return [
            'date' => $date->format('Y-m-d'),
            'location' => ['lat' => $lat, 'lng' => $lng],
            'tides' => $tides,
            'tidal_range_m' => round($tidalRange, 1),
            'spring_or_neap' => rand(0, 1) ? 'spring' : 'neap',
            'best_fishing_windows' => [
                [
                    'start' => sprintf('%02d:%02d', max(0, ($tides[0]['time'] ?? '06:00') ? intval($tides[0]['time']) - 2 : 4), 0),
                    'end' => $tides[0]['time'] ?? '06:00',
                    'reason' => 'Incoming tide - fish feeding actively',
                ],
                [
                    'start' => $tides[2]['time'] ?? '14:00',
                    'end' => sprintf('%02d:%02d', min(23, intval($tides[2]['time'] ?? '14:00') + 2), 0),
                    'reason' => 'Around high tide - peak activity',
                ],
            ],
        ];
    }

    public function getProviderName(): string
    {
        return 'demo';
    }
}
</boltAction>

