<boltAction type="file" filePath="app/Services/HuntBriefingService.php" contentType="text/plain">
<?php

namespace App\Services;

use App\Models\Hunt;
use App\Models\HuntBriefing;
use App\Models\HuntChecklistItem;
use App\Services\Providers\WeatherProviderInterface;
use App\Services\Providers\TideProviderInterface;
use App\Services\Providers\SpeciesInfoProviderInterface;
use Illuminate\Support\Facades\Cache;
use Illuminate\Support\Facades\DB;

class HuntBriefingService
{
    public function __construct(
        private WeatherProviderInterface $weatherProvider,
        private TideProviderInterface $tideProvider,
        private SpeciesInfoProviderInterface $speciesProvider,
    ) {}

    public function generateBriefing(Hunt $hunt): HuntBriefing
    {
        $cacheKey = "hunt_briefing_{$hunt->id}_" . $hunt->updated_at->timestamp;

        return Cache::remember($cacheKey, 3600, function () use ($hunt) {
            return DB::transaction(function () use ($hunt) {
                $lat = $hunt->latitude ?? 51.5074;
                $lng = $hunt->longitude ?? -0.1278;
                $date = $hunt->starts_at;
                $month = (int) $date->format('n');

                // Fetch data from providers
                $weatherData = $this->weatherProvider->getForecast($lat, $lng, $date);
                $tideData = $hunt->is_coastal ? $this->tideProvider->getTides($lat, $lng, $date) : null;
                $speciesData = $this->speciesProvider->getSpeciesForLocation($lat, $lng, $month, $hunt->is_coastal);
                $baitSuggestions = $this->speciesProvider->getBaitSuggestions($speciesData);

                $gearSuggestions = $this->generateGearSuggestions($hunt, $speciesData, $weatherData);
                $timingTips = $this->generateTimingTips($hunt, $weatherData, $tideData);

                $isDemoData = $this->weatherProvider->getProviderName() === 'demo';

                // Delete old briefings
                $hunt->briefings()->delete();

                $briefing = HuntBriefing::create([
                    'hunt_id' => $hunt->id,
                    'weather_data' => $weatherData,
                    'tide_data' => $tideData,
                    'species_data' => $speciesData,
                    'bait_suggestions' => $baitSuggestions,
                    'gear_suggestions' => $gearSuggestions,
                    'timing_tips' => $timingTips,
                    'weather_provider' => $this->weatherProvider->getProviderName(),
                    'tide_provider' => $this->tideProvider->getProviderName(),
                    'species_provider' => $this->speciesProvider->getProviderName(),
                    'is_demo_data' => $isDemoData,
                    'generated_at' => now(),
                    'expires_at' => now()->addHours(6),
                ]);

                // Generate checklist items
                $this->generateChecklist($hunt, $gearSuggestions, $baitSuggestions, $speciesData);

                return $briefing;
            });
        });
    }

    private function generateGearSuggestions(Hunt $hunt, array $species, array $weather): array
    {
        $gear = [
            'rods' => [],
            'reels' => [],
            'line' => [],
            'tackle' => [],
            'accessories' => [],
            'clothing' => [],
            'safety' => [],
        ];

        if ($hunt->is_coastal) {
            $gear['rods'][] = '12ft beachcaster (for distance casting)';
            $gear['rods'][] = '10ft spinning rod (for lure fishing)';
            $gear['reels'][] = 'Fixed spool reel (6000 size) with 15lb line';
            $gear['reels'][] = 'Multiplier reel for beachcaster';
            $gear['line'][] = '15-20lb monofilament mainline';
            $gear['line'][] = '30lb shock leader';
            $gear['tackle'][] = 'Size 1/0-4/0 hooks';
            $gear['tackle'][] = '4-6oz grip leads';
            $gear['tackle'][] = 'Pulley pennel rigs';
            $gear['tackle'][] = 'Running ledger rigs';
            $gear['tackle'][] = 'Swivels and beads';
        } else {
            $hasLargeFish = collect($species)->contains(fn($s) => in_array($s['name'] ?? '', ['Carp (Common)', 'Pike', 'Barbel']));
            if ($hasLargeFish) {
                $gear['rods'][] = '12ft 2.75lb test curve carp rod';
                $gear['reels'][] = 'Baitrunner reel (4000-6000 size)';
                $gear['line'][] = '12-15lb monofilament or 20lb braid';
            }
            $gear['rods'][] = '12-13ft float rod';
            $gear['rods'][] = '11ft quiver tip feeder rod';
            $gear['reels'][] = 'Fixed spool reel (3000-4000 size)';
            $gear['line'][] = '4-8lb mainline';
            $gear['line'][] = '3-6lb hooklength';
            $gear['tackle'][] = 'Selection of hooks (sizes 8-18)';
            $gear['tackle'][] = 'Float selection (wagglers, sticks)';
            $gear['tackle'][] = 'Split shot and olivettes';
            $gear['tackle'][] = 'Feeders (cage, method, maggot)';
            $gear['tackle'][] = 'Landing net (min 36 inch)';
            $gear['tackle'][] = 'Unhooking mat';
        }

        $gear['accessories'][] = 'Rod rest / bank sticks';
        $gear['accessories'][] = 'Tackle box';
        $gear['accessories'][] = 'Bait box / cool bag';
        $gear['accessories'][] = 'Scissors / line cutters';
        $gear['accessories'][] = 'Disgorger / forceps';
        $gear['accessories'][] = 'Headtorch (if fishing dawn/dusk)';
        $gear['accessories'][] = 'Folding chair or seat box';

        $temp = $weather['high_c'] ?? 15;
        if ($temp < 10) {
            $gear['clothing'][] = 'Thermal base layers';
            $gear['clothing'][] = 'Insulated waterproof jacket';
            $gear['clothing'][] = 'Warm hat and gloves';
            $gear['clothing'][] = 'Thermal boots / wellies';
        } elseif ($temp < 18) {
            $gear['clothing'][] = 'Layered clothing';
            $gear['clothing'][] = 'Waterproof jacket (just in case)';
            $gear['clothing'][] = 'Comfortable boots';
        } else {
            $gear['clothing'][] = 'Light breathable clothing';
            $gear['clothing'][] = 'Sun hat and sunglasses';
            $gear['clothing'][] = 'Sunscreen (SPF 30+)';
        }

        if (($weather['precipitation_chance'] ?? 0) > 40) {
            $gear['clothing'][] = 'Waterproof trousers';
            $gear['accessories'][] = 'Brolly / shelter';
        }

        $gear['safety'][] = 'First aid kit';
        $gear['safety'][] = 'Mobile phone (charged)';
        $gear['safety'][] = 'Drinking water and snacks';
        if ($hunt->is_coastal) {
            $gear['safety'][] = 'Tide timetable (printed backup)';
            $gear['safety'][] = 'Whistle';
            $gear['safety'][] = 'Buoyancy aid (if rock fishing)';
        }

        return $gear;
    }

    private function generateTimingTips(Hunt $hunt, array $weather, ?array $tides): array
    {
        $tips = [];

        $sunrise = $weather['sunrise'] ?? '06:30';
        $sunset = $weather['sunset'] ?? '18:00';

        $tips[] = [
            'icon' => '🌅',
            'title' => 'Dawn & Dusk',
            'tip' => "Sunrise at {$sunrise}, sunset at {$sunset}. The hour either side of these times is often the most productive.",
        ];

        if ($hunt->is_coastal && $tides) {
            $highTides = array_filter($tides['tides'] ?? [], fn($t) => $t['type'] === 'high');
            foreach ($highTides as $ht) {
                $tips[] = [
                    'icon' => '🌊',
                    'title' => 'High Tide at ' . $ht['time'],
                    'tip' => "Fish the last 2 hours of the incoming tide and first hour of the ebb for best results. Height: {$ht['height_m']}m.",
                ];
            }

            $springNeap = $tides['spring_or_neap'] ?? 'neap';
            $tips[] = [
                'icon' => '🌙',
                'title' => ucfirst($springNeap) . ' Tide',
                'tip' => $springNeap === 'spring'
                    ? 'Spring tides today - stronger currents, more water movement. Great for bass and cod but be careful of fast-rising water.'
                    : 'Neap tides today - gentler currents. Good for float fishing and lighter tackle work.',
            ];
        }

        $wind = $weather['avg_wind_mph'] ?? 10;
        if ($wind > 15) {
            $tips[] = [
                'icon' => '💨',
                'title' => 'Windy Conditions',
                'tip' => "Winds around {$wind}mph expected. Fish into the wind where possible - food gets blown to the windward bank/shore. Use heavier weights.",
            ];
        } else {
            $tips[] = [
                'icon' => '🍃',
                'title' => 'Light Winds',
                'tip' => "Light winds ({$wind}mph) - great conditions for float fishing and surface techniques.",
            ];
        }

        $precip = $weather['precipitation_chance'] ?? 20;
        if ($precip > 50) {
            $tips[] = [
                'icon' => '🌧️',
                'title' => 'Rain Expected',
                'tip' => 'Rain can be brilliant for fishing! It oxygenates the water and washes food in. Fish often feed more actively during light rain.',
            ];
        }

        $pressure = $weather['pressure_mb'] ?? 1015;
        if ($pressure > 1020) {
            $tips[] = [
                'icon' => '📊',
                'title' => 'High Pressure',
                'tip' => "Pressure at {$pressure}mb (high). Fish may be less active - try fishing deeper and slower. Early morning and late evening best.",
            ];
        } elseif ($pressure < 1010) {
            $tips[] = [
                'icon' => '📊',
                'title' => 'Low Pressure',
                'tip' => "Pressure at {$pressure}mb (low). Fish tend to feed more aggressively in low pressure. Great conditions!",
            ];
        }

        return $tips;
    }

    private function generateChecklist(Hunt $hunt, array $gear, array $bait, array $species): void
    {
        // Clear existing auto-generated items
        $hunt->checklistItems()->where('is_custom', false)->delete();

        $items = [];
        $order = 0;

        // Gear items
        foreach ($gear as $category => $categoryItems) {
            foreach ($categoryItems as $item) {
                $items[] = [
                    'hunt_id' => $hunt->id,
                    'category' => ucfirst($category),
                    'item' => $item,
                    'is_checked' => false,
                    'sort_order' => $order++,
                    'is_custom' => false,
                    'created_at' => now(),
                    'updated_at' => now(),
                ];
            }
        }

        // Bait items
        foreach ($bait as $speciesName => $baits) {
            foreach (array_slice($baits, 0, 3) as $b) {
                $items[] = [
                    'hunt_id' => $hunt->id,
                    'category' => 'Bait',
                    'item' => $b,
                    'notes' => "For {$speciesName}",
                    'is_checked' => false,
                    'sort_order' => $order++,
                    'is_custom' => false,
                    'created_at' => now(),
                    'updated_at' => now(),
                ];
            }
        }

        // Essential items
        $essentials = [
            'Rod licence (check it\'s valid!)',
            'Day ticket / club card (if needed)',
            'Bait - purchased and ready',
            'Food and drinks for the session',
            'Check weather forecast morning of',
        ];

        foreach ($essentials as $e) {
            $items[] = [
                'hunt_id' => $hunt->id,
                'category' => 'Essentials',
                'item' => $e,
                'is_checked' => false,
                'sort_order' => $order++,
                'is_custom' => false,
                'created_at' => now(),
                'updated_at' => now(),
            ];
        }

        HuntChecklistItem::insert($items);
    }
}
