use Illuminate\Database\Eloquent\Relations\HasMany;
use Illuminate\Database\Eloquent\Relations\HasOne;
use Illuminate\Support\Str;

class Hunt extends Model
{
    use SoftDeletes;

    protected $fillable = [
        'user_id', 'title', 'location_name', 'region', 'country', 'latitude', 'longitude',
        'is_coastal', 'starts_at', 'ends_at', 'notes', 'share_token', 'is_public', 'status',
    ];

