    {
        return $this->hasOne(HuntBriefing::class)->latestOfMany();
    }

    public function briefings(): HasMany
    {
        return $this->hasMany(HuntBriefing::class);
    }

    public function getShareUrlAttribute(): string
    {
        return route('hunts.shared', $this->share_token);
    }

    public function getDurationHoursAttribute(): float
    {
        return $this->starts_at->diffInHours($this->ends_at);
    }
}
