<?php

namespace App\Services;

use App\Models\Badge;
use App\Models\User;

class BadgeService
{
    public function checkAndAwardBadges(User $user): array
    {
        $awarded = [];
        $badges = Badge::all();

        foreach ($badges as $badge) {
            if ($user->badges()->where('badge_id', $badge->id)->exists()) {
                continue;
            }

            $earned = match ($badge->criteria_type) {
                'posts_count' => $user->posts()->count() >= $badge->criteria_count,
                'species_count' => $user->posts()->distinct('species')->whereNotNull('species')->count('species') >= $badge->criteria_count,
                'hunts_count' => $user->hunts()->count() >= $badge->criteria_count,
                'comments_count' => $user->comments()->count() >= $badge->criteria_count,
                'likes_received' => $user->posts()->withCount('likes')->get()->sum('likes_count') >= $badge->criteria_count,
                default => false,
            };

            if ($earned) {
                $user->badges()->attach($badge->id, ['earned_at' => now()]);
                $awarded[] = $badge;
            }
        }

        return $awarded;
    }
}
</boltAction>

