use App\Services\Providers\DemoTideProvider;
use App\Services\Providers\DemoSpeciesInfoProvider;
use App\Services\Providers\WeatherProviderInterface;
use App\Services\Providers\TideProviderInterface;
use App\Services\Providers\SpeciesInfoProviderInterface;
use Illuminate\Support\Facades\Gate;
use Illuminate\Support\ServiceProvider;

class AppServiceProvider extends ServiceProvider
{
    public function register(): void
    {
        // Bind provider interfaces - swap implementations here when adding real APIs
        $this->app->bind(WeatherProviderInterface::class, function () {
            $provider = config('fishhunt.weather.provider', 'demo');
            return match ($provider) {
                // 'openweather' => new OpenWeatherProvider(config('fishhunt.weather.api_key')),
                default => new DemoWeatherProvider(),
            };
        });

        $this->app->bind(TideProviderInterface::class, function () {
            $provider = config('fishhunt.tides.provider', 'demo');
            return match ($provider) {
                // 'worldtides' => new WorldTidesProvider(config('fishhunt.tides.api_key')),
                default => new DemoTideProvider(),
            };
        });

        $this->app->bind(SpeciesInfoProviderInterface::class, function () {
            $provider = config('fishhunt.species.provider', 'demo');
            return match ($provider) {
                default => new DemoSpeciesInfoProvider(),
            };
        });
    }

    public function boot(): void
    {
        // Super admin gate - admins bypass all authorization
        Gate::before(function (User $user, string $ability) {
            if ($user->isAdmin()) {
                return true;
            }
            return null;
        });

        // Define gates based on permissions
        Gate::define('manage-users', fn(User $user) => $user->hasPermission('manage-users'));
        Gate::define('manage-roles', fn(User $user) => $user->hasPermission('manage-roles'));
        Gate::define('manage-settings', fn(User $user) => $user->hasPermission('manage-settings'));
        Gate::define('moderate-content', fn(User $user) => $user->hasPermission('moderate-content'));
        Gate::define('delete-any-post', fn(User $user) => $user->hasPermission('delete-any-post'));
        Gate::define('delete-any-comment', fn(User $user) => $user->hasPermission('delete-any-comment'));
        Gate::define('view-reports', fn(User $user) => $user->hasPermission('view-reports'));
        Gate::define('create-post', fn(User $user) => $user->hasPermission('create-post'));
        Gate::define('create-hunt', fn(User $user) => $user->hasPermission('create-hunt'));
        Gate::define('create-comment', fn(User $user) => $user->hasPermission('create-comment'));
        Gate::define('like-post', fn(User $user) => $user->hasPermission('like-post'));
    }
}
