<boltAction type="file" filePath="app/Http/Middleware/CheckRole.php" contentType="text/plain">
<?php

namespace App\Http\Middleware;

use Closure;
use Illuminate\Http\Request;
use Symfony\Component\HttpFoundation\Response;

class CheckRole
{
    public function handle(Request $request, Closure $next, string ...$roles): Response
    {
        if (!$request->user()) {
            abort(403, 'Unauthorized');
        }

        if (!$request->user()->hasAnyRole($roles)) {
            abort(403, 'You do not have the required role to access this page.');
        }

        return $next($request);
    }
}
</boltAction>

<boltAction type="file" filePath="app/Http/Middleware/CheckPermission.php" contentType="text/plain">
<?php

namespace App\Http\Middleware;

use Closure;
use Illuminate\Http\Request;
use Symfony\Component\HttpFoundation\Response;

class CheckPermission
{
    public function handle(Request $request, Closure $next, string $permission): Response
    {
        if (!$request->user()) {
            abort(403, 'Unauthorized');
        }

        if (!$request->user()->hasPermission($permission) && !$request->user()->isAdmin()) {
            abort(403, 'You do not have permission to perform this action.');
        }

        return $next($request);
    }
}
